import{_ as t,o,c as r,ag as a}from"./chunks/framework.1N8rnUr9.js";const g=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md","lastUpdated":1775715475000}'),i={name:"guide/introduction.md"};function n(s,e,d,l,u,c){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p><strong>TubeBay</strong> is a modern, lightweight WordPress plugin that bridges the gap between your YouTube channel and your WooCommerce store. Designed with simplicity and performance in mind, it allows you to automatically synchronize your YouTube library and map videos directly to your products.</p><p>By integrating product videos, you can significantly increase customer engagement, trust, and conversion rates without the manual overhead of managing individual embed codes.</p><h2 id="why-use-tubebay" tabindex="-1">Why Use TubeBay? <a class="header-anchor" href="#why-use-tubebay" aria-label="Permalink to &quot;Why Use TubeBay?&quot;">​</a></h2><p>TubeBay is perfect for WooCommerce store owners who create video content on YouTube and want to display it professionally on their product pages:</p><ul><li><strong>Auto-Syncing:</strong> No more manual embedding. Your latest videos are pulled into your dashboard automatically.</li><li><strong>Smart Mapping:</strong> Link videos to products in seconds using our intuitive search-and-select interface.</li><li><strong>Flexible Playback:</strong> Embedded players are optimized for performance and mobile responsiveness.</li><li><strong>Visual Placement:</strong> Choose exactly where the video appears on the product page via the admin settings.</li></ul><h2 id="key-highlights" tabindex="-1">Key Highlights <a class="header-anchor" href="#key-highlights" aria-label="Permalink to &quot;Key Highlights&quot;">​</a></h2><h3 id="hybrid-performance" tabindex="-1">Hybrid Performance <a class="header-anchor" href="#hybrid-performance" aria-label="Permalink to &quot;Hybrid Performance&quot;">​</a></h3><p>TubeBay is built for speed, ensuring your product pages remain fast and responsive:</p><table tabindex="0"><thead><tr><th>Layer</th><th>Technology</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Admin Dashboard</strong></td><td>React SPA</td><td>Smooth, modern interface for managing videos</td></tr><tr><td><strong>Backend Sync</strong></td><td>WP REST API</td><td>Secure, asynchronous data fetching from YouTube</td></tr><tr><td><strong>Frontend Embeds</strong></td><td>Lightweight HTML5/YouTube API</td><td>SEO-friendly, non-blocking video playback</td></tr></tbody></table><h3 id="core-workflow" tabindex="-1">Core Workflow <a class="header-anchor" href="#core-workflow" aria-label="Permalink to &quot;Core Workflow&quot;">​</a></h3><ul><li><strong>Connect:</strong> Securely link your YouTube account via Google OAuth 2.0 or Manual API keys.</li><li><strong>Manage:</strong> Browse your entire YouTube library directly within the WordPress admin.</li><li><strong>Map:</strong> Assign videos to specific WooCommerce products with one click.</li><li><strong>Configure:</strong> Customize player behavior (autoplay, controls, mute) and placement.</li><li><strong>Automate:</strong> Let TubeBay keep your video library up-to-date with periodic syncs.</li></ul><h2 id="version-support" tabindex="-1">Version Support <a class="header-anchor" href="#version-support" aria-label="Permalink to &quot;Version Support&quot;">​</a></h2><p>TubeBay is designed to work with modern WordPress and WooCommerce environments. For specific details, see our <a href="/tubebay/guide/requirements.html">Requirements</a> page.</p>',14)])])}const p=t(i,[["render",n]]);export{g as __pageData,p as default};
